import { Card, CardHeader, IconButton} from '@material-ui/core'
import { MoreVert } from '@material-ui/icons'
import React from 'react'

export default function SubjectCards({ subject }) {
  return (
    <div>
        <Card>
            <CardHeader 
              action={
                <IconButton>
                  <MoreVert/>
                </IconButton>
              }
              title = {subject.title}
            />
        </Card>
    </div>
  )
}
